const REQUIRED_CONTEXT_HEADINGS = [
  '## Feature Summary',
  '## Feature Classification',
  '## Source Inventory',
  '## Primary User Journeys',
  '## Entry Points',
  '## Core Capability Families',
  '## Error / Recovery Behaviors',
  '## Known Risks / Regressions',
  '## Permissions / Auth / Data Constraints',
  '## Environment / Platform Constraints',
  '## Setup / Fixtures Needed',
  '## Unsupported / Deferred / Ambiguous',
  '## Mandatory Coverage Candidates',
  '## Traceability Map',
];

const BANNED_VAGUE_PHRASES = [
  'verify correct behavior',
  'verify expected behavior',
  'ensure it works',
  'test parity',
  'perform another valid action',
  'confirm functionality',
  'validate integration',
  'check the feature',
];

const GENERIC_EXPECTED_RESULT_PHRASES = [
  'remains usable',
  'works correctly',
  'correct behavior',
  'safe understandable way',
];

const IMPLEMENTATION_TOKENS = [
  'service',
  'bridge api',
  'bridge function',
  'internal api',
  'hook',
  'sdk',
  'renderproxy',
  'updatefuncreactcomponent',
];

const STOPWORDS = new Set([
  'the',
  'and',
  'for',
  'with',
  'after',
  'before',
  'still',
  'next',
  'action',
  'comment',
  'trigger',
  'unclear',
]);

const CONTRADICTORY_TOKEN_GROUPS = [
  ['enable', 'disable'],
  ['enabled', 'disabled'],
  ['read', 'unread'],
  ['open', 'close'],
  ['opened', 'closed'],
  ['valid', 'invalid'],
  ['grant', 'revoke'],
  ['allow', 'deny'],
  ['success', 'failure'],
  ['online', 'offline'],
];

const CANONICAL_TOP_LAYERS = [
  'EndToEnd',
  'Core Functional Flows',
  'Error Handling / Recovery',
  'Regression / Known Risks',
  'Compatibility',
  'Security',
  'i18n',
  'Accessibility',
  'Performance / Resilience',
  'Out of Scope / Assumptions',
];

const REQUIRED_CHECKPOINTS = [
  'Checkpoint 1',
  'Checkpoint 2',
  'Checkpoint 3',
  'Checkpoint 4',
  'Checkpoint 5',
  'Checkpoint 6',
  'Checkpoint 7',
  'Checkpoint 8',
